mapper.select:
SELECT STOCK_NAME
FROM STOCKS
WHERE STOCK_ID = #{stockId}

mapper.update:
MERGE INTO STOCKS S USING (
SELECT #{stockInfo.stockId} AS STOCK_ID, #{stockInfo.stockName} AS STOCK_NAME, 'Y' AS IS_ACTIVE FROM DUAL
) V ON (S.STOCK_ID = V.STOCK_ID) WHEN MATCHED THEN UPDATE SET S.STOCK_NAME = V.STOCK_NAME, S.IS_ACTIVE = V.IS_ACTIVE WHEN NOT MATCHED THEN INSERT (STOCK_ID, STOCK_NAME, STOCK_SECTOR, IS_ACTIVE) VALUES (V.STOCK_ID, V.STOCK_NAME, '-', V.IS_ACTIVE)
